import { t as prisma } from "../../../../../../../chunks/prisma.js";
import { error } from "@sveltejs/kit";
//#region src/routes/(protected)/dashboard/certificates/[id]/view/+page.server.ts
var load = async ({ params }) => {
	const certificate = await prisma.certificate.findUnique({ where: { id: params.id } });
	if (!certificate) throw error(404, "Certificate not found");
	return { certificate };
};
//#endregion
export { load };
